  ('bookkeeper-moex-00011', 'bookkeeper', 'bookkeeper-moex-114-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司3月31日銀行對帳單顯示餘額為$72,000，而公司帳列銀行存款餘額為$85,000。經分析兩 者差異來自下列情況： ⑴銀行代收乙客戶開立的票據款$20,500，公司尚未入帳。 ⑵銀行存款本月的利息收入為$500，公司尚未入帳。 ⑶銀行收取帳戶手續費$200，公司尚未入帳。 ⑷甲公司於3月15日送存的支票因存款不足而退票，金額$12,000，銀行尚未通知甲公司。 ⑸甲公司開立支票付款，至3月31日仍有未兌現金額$5,000。 ⑹3月31日甲公司送存的支票有一筆在途存款$26,800。 請問3月底正確的銀行存款餘額應為多少？', '["$102,600", "$115,600", "$96,000", "$93,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "6d92ab6ec67a", "answer_pdf_sha1": "b1533b8ff15e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114180", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
